class o{constructor(){this.init()}init(){this.setupTimeline(),this.setupActions()}setupTimeline(){document.querySelectorAll(".timeline-item").forEach(e=>{const a=e.querySelector(".step-circle"),n=e.querySelector(".step-info");a&&n&&(e.addEventListener("mouseenter",()=>{a.classList.contains("current")||(a.style.transform="scale(1.1)")}),e.addEventListener("mouseleave",()=>{a.classList.contains("current")||(a.style.transform="")}))})}setupActions(){const t=document.getElementById("btnAprovarDoc");t&&t.addEventListener("click",()=>this.confirmarAcao("aprovar"));const e=document.getElementById("btnSolicitarRevisao");e&&e.addEventListener("click",()=>this.confirmarAcao("revisao"));const a=document.getElementById("btnAvancarEtapa");a&&a.addEventListener("click",()=>this.confirmarAcao("avancar"))}confirmarAcao(t){confirm({aprovar:"Confirma a aprovação da documentação?",revisao:"Deseja solicitar revisão da documentação?",avancar:"Confirma o avanço para a próxima etapa?"}[t]||"Confirma esta ação?")&&this.executarAcao(t)}async executarAcao(t){const e=document.getElementById(`form${t.charAt(0).toUpperCase()+t.slice(1)}`);e&&e.submit()}}document.addEventListener("DOMContentLoaded",()=>{window.detalhesPage=new o});
